// CLIOverrides carries per-invocation flag values that override
// project config. Zero values mean "no override; use config".
// Pointer fields distinguish "explicit value" from "not set".
type CLIOverrides struct {
	Harness       string
	Model         string
	Provider      string
	ModelRef      string
	Profile       string
	Effort        string
	Permissions   string
	MinTier       string
	MaxTier       string
	// MinPower and MaxPower are optional numeric routing power bounds (1-10
