package agent

// power_bounds.go provides compile-time adapters and helpers for the upstream
// agent power-bounds contract (MinPower/MaxPower on ServiceExecuteRequest and
// Power on ModelInfo). These fields were introduced in agent v0.9.25.
//
// Having references here ensures DDx fails to compile if the upstream removes
// them, surfacing a breaking contract change immediately.

import agentlib "github.com/DocumentDrivenDX/agent"

// powerBoundsCompileCheck is a compile-time reference to the MinPower,
// MaxPower, and ModelInfo.Power fields introduced in agent v0.9.25.
// This function is never called; it exists only to prevent the upstream
// fields from being silently removed without a DDx build failure.
func powerBoundsCompileCheck() {
	var req agentlib.ServiceExecuteRequest
	_ = req.MinPower
	_ = req.MaxPower
	var m agentlib.ModelInfo
	_ = m.Power
}

// findModelPower returns the power number for modelID from the catalog list.
// Returns 0 if the model is not found or has no power assigned.
func findModelPower(models []agentlib.ModelInfo, modelID string) int {
	for _, m := range models {
		if m.ID == modelID {
			return m.Power
		}
	}
	return 0
}

